// ═══ CENTRALIZED CONFIGURATION v4.0 ═══
// All configurable values in one place. Change here, applies everywhere.

const CONFIG = {
  // NocoDB
  nocodb: {
    baseUrl: $env.NOCODB_BASE_URL || 'http://nocodb:8080',
    apiPrefix: '/api/v1/db/data/noco',
    orgId: $env.NOCODB_ORG_ID || 'ppxzhw4b32456e0',
    tables: {
      structures: $env.NOCODB_TABLE_STRUCTURES || 'mvd9w6n0m6uaon1',
      briefs: $env.NOCODB_TABLE_BRIEFS || 'mwd3au8e0j3vrxo',
      results: $env.NOCODB_TABLE_RESULTS || 'mvuttgzgqpknpyj',
      projects: $env.NOCODB_TABLE_PROJECTS || 'mprojects001'
    },
    pageSize: 200,
    maxRows: 5000,
    authEmail: $env.NOCODB_EMAIL,
    authPassword: $env.NOCODB_PASSWORD
  },
  // LLM
  llm: {
    provider: 'groq',
    model: $env.LLM_MODEL || 'llama-3.3-70b-versatile',
    maxTokens: 8192,
    temperature: 0.15,
    apiKey: $env.GROQ_API_KEY,
    baseUrl: 'https://api.groq.com/openai/v1/chat/completions',
    retryAttempts: 3,
    retryDelayMs: 3000,
    batchDelayMs: 2500,
    tokenBudget: parseInt($env.LLM_TOKEN_BUDGET) || 500000
  },
  // Crawler
  crawler: {
    timeoutMs: 20000,
    maxRedirects: 5,
    maxTextLength: 6000,
    userAgent: 'SEOBot/4.0 (+https://example.com/bot)',
    respectRobotsTxt: true,
    cacheTtlHours: 24
  },
  // ML Service
  ml: {
    url: $env.ML_SERVICE_URL || 'http://ml-service:8000',
    timeoutMs: 15000,
    enabled: ($env.ML_SERVICE_ENABLED || 'false') === 'true'
  },
  // Analysis
  analysis: {
    batchSize: { min: 1, max: 10, default: 3 },
    version: 'v4.0_pro',
    keywordDensity: {
      commercial: { min: 1.5, max: 3.0 },
      informational: { min: 1.0, max: 2.0 }
    },
    scoring: {
      excellent: { min: 9 },
      good: { min: 7 },
      average: { min: 5 },
      poor: { min: 1 }
    }
  },
  // Alerts
  alerts: {
    webhookUrl: $env.ALERT_WEBHOOK_URL || '',
    provider: $env.ALERT_PROVIDER || 'telegram',
    minScoreThreshold: 6,
    enabled: !!$env.ALERT_WEBHOOK_URL
  }
};

return [{ json: { config: CONFIG } }];

const headers = $input.first().json.headers || {};
const apiKey = headers['x-api-key'] || headers['X-Api-Key'] || '';
const expectedKey = $env.WORKFLOW_API_KEY || '';

if (expectedKey && apiKey !== expectedKey) {
  const err = new Error('HTTP 401: Invalid or missing API key');
  err.httpCode = 401;
  throw err;
}

// Pass through with request metadata
const item = $input.first().json;
return [{ json: {
  ...item,
  _auth: { authenticated: !!expectedKey, ip: headers['x-forwarded-for'] || 'unknown' }
}}];

const body = $input.first().json.body || $input.first().json;
const config = $('Init Config').first().json.config;
const { niche, city, project_id, batch_size, domain, crawl_pages, force_recrawl } = body;

// ── Strict validation ──
const errors = [];
if (!niche || typeof niche !== 'string' || niche.trim().length < 2)
  errors.push('niche: обязательно, строка, мин. 2 символа');
if (!city || typeof city !== 'string' || city.trim().length < 2)
  errors.push('city: обязательно, строка');
if (!project_id || typeof project_id !== 'string' || !/^[a-zA-Z0-9_-]+$/.test(project_id))
  errors.push('project_id: обязательно, только [a-zA-Z0-9_-]');

// Domain SSRF protection
let safeDomain = (domain || '').trim();
if (safeDomain) {
  try {
    const url = new URL(safeDomain.startsWith('http') ? safeDomain : 'https://' + safeDomain);
    const forbidden = ['localhost', '127.0.0.1', '0.0.0.0', '::1', 'metadata.google', '169.254.'];
    if (forbidden.some(f => url.hostname.includes(f)))
      errors.push('domain: запрещённый адрес');
    if (!['http:', 'https:'].includes(url.protocol))
      errors.push('domain: только http/https');
    safeDomain = url.origin;
  } catch(e) { errors.push('domain: невалидный URL'); }
}

if (errors.length > 0) {
  throw new Error('Validation errors:\n• ' + errors.join('\n• '));
}

const bs = config.analysis.batchSize;
const safeBatch = Math.min(Math.max(parseInt(batch_size) || bs.default, bs.min), bs.max);

return [{ json: {
  niche: niche.trim(),
  city: city.trim(),
  project_id: project_id.trim(),
  domain: safeDomain,
  batch_size: safeBatch,
  crawl_pages: crawl_pages !== false,
  force_recrawl: !!force_recrawl,
  is_cron_trigger: false,
  workflow_version: config.analysis.version,
  started_at: new Date().toISOString(),
  _config: config
}}];

const config = $('Init Config').first().json.config;

// Fetch active projects from NocoDB instead of ENV
const authResp = await fetch(config.nocodb.baseUrl + '/api/v1/auth/user/signin', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ email: config.nocodb.authEmail, password: config.nocodb.authPassword })
});
const authData = await authResp.json();
if (!authData.token) { console.log('[Cron] NocoDB auth failed'); return []; }

const tableUrl = `${config.nocodb.baseUrl}${config.nocodb.apiPrefix}/${config.nocodb.orgId}/${config.nocodb.tables.projects}`;
const resp = await fetch(tableUrl + '?where=(is_active,eq,true)&limit=100', {
  headers: { 'xc-auth': authData.token }
});
const data = await resp.json();
const projects = data.list || [];

if (projects.length === 0) {
  console.log('[Cron] No active projects found');
  return [];
}

return projects.map(p => ({ json: {
  niche: p.niche,
  city: p.city,
  project_id: p.project_id,
  domain: p.domain || '',
  batch_size: config.analysis.batchSize.default,
  crawl_pages: true,
  force_recrawl: false,
  is_cron_trigger: true,
  workflow_version: config.analysis.version,
  started_at: new Date().toISOString(),
  _config: config
}}));

const validate = $('Validate Input').first().json;
const config = validate._config;
const token = $('NocoDB Auth').first().json.body?.token || $('NocoDB Auth').first().json.token;

if (!token) throw new Error('NocoDB auth failed: no token received');

// ── Reusable paginated fetch ──
async function fetchTable(tableId, projectId, extraFields) {
  const baseUrl = `${config.nocodb.baseUrl}${config.nocodb.apiPrefix}/${config.nocodb.orgId}/${tableId}`;
  let allRows = [], offset = 0;
  const ps = config.nocodb.pageSize;
  const maxRows = config.nocodb.maxRows;

  while (offset < maxRows) {
    const url = `${baseUrl}?where=(project_id,eq,${projectId})&limit=${ps}&offset=${offset}`;
    const resp = await fetch(url, { headers: { 'xc-auth': token } });
    if (!resp.ok) throw new Error(`NocoDB fetch error: ${resp.status} ${await resp.text()}`);
    const data = await resp.json();
    const rows = data.list || [];
    allRows = allRows.concat(rows);
    if (rows.length < ps) break;
    offset += ps;
  }
  return allRows;
}

const projectId = validate.project_id;

// Parallel fetch all 3 tables
const [structures, briefs, existingRows] = await Promise.all([
  fetchTable(config.nocodb.tables.structures, projectId),
  fetchTable(config.nocodb.tables.briefs, projectId),
  fetchTable(config.nocodb.tables.results, projectId)
]);

if (structures.length === 0) {
  throw new Error('Нет структур для project_id: ' + projectId);
}

// Build lookup maps
const briefsMap = {};
briefs.forEach(b => { if (b.page_slug) briefsMap[b.page_slug] = b; });

const existingMap = {};
existingRows.forEach(r => { if (r.page_slug) existingMap[r.page_slug] = r; });

// Deduplicate structures by slug
const seen = new Set();
const uniqueStructures = structures.filter(s => {
  const slug = s.recommended_url || '';
  if (!slug || seen.has(slug)) return false;
  seen.add(slug);
  return true;
});

console.log(`[v4.0] Fetched: ${uniqueStructures.length} structures (deduped from ${structures.length}), ${briefs.length} briefs, ${existingRows.length} existing results`);

return [{ json: {
  structures: uniqueStructures,
  briefs_map: briefsMap,
  existing_map: existingMap,
  token: token,
  counts: {
    structures: uniqueStructures.length,
    briefs: briefs.length,
    existing: existingRows.length,
    duplicates_removed: structures.length - uniqueStructures.length
  }
}}];

const data = $input.first().json;
const validate = $('Validate Input').first().json;
const structures = data.structures;

if (!validate.crawl_pages || !validate.domain) {
  return [{ json: { text_map: {}, crawled: 0, skipped: true, _passthrough: data } }];
}

// Validate and build URL list
const urls = [];
const skipped = [];

for (const p of structures) {
  const slug = p.recommended_url || '';
  if (!slug) { skipped.push({ slug: '(empty)', reason: 'no_slug' }); continue; }

  let fullUrl;
  try {
    fullUrl = slug.startsWith('http') ? slug : validate.domain.replace(/\/$/, '') + slug;
    new URL(fullUrl); // validate URL format
  } catch(e) {
    skipped.push({ slug, reason: 'invalid_url' });
    continue;
  }

  // Skip already analyzed pages if not force_recrawl
  if (!validate.force_recrawl && data.existing_map[slug]
      && data.existing_map[slug].updated_at) {
    const lastUpdate = new Date(data.existing_map[slug].updated_at);
    const hoursSince = (Date.now() - lastUpdate.getTime()) / 3600000;
    if (hoursSince < (validate._config?.crawler?.cacheTtlHours || 24)) {
      skipped.push({ slug, reason: 'cache_fresh', hours: Math.round(hoursSince) });
      continue;
    }
  }

  urls.push({ slug, url: fullUrl, page_type: p.page_type || 'commercial' });
}

if (skipped.length > 0) {
  console.log(`[v4.0] Crawl: ${urls.length} to crawl, ${skipped.length} skipped`);
}

if (urls.length === 0) {
  return [{ json: { text_map: {}, crawled: 0, skipped: true, skip_reason: 'all_cached_or_invalid', _passthrough: data } }];
}

return urls.map(u => ({ json: { ...u, _passthrough: data } }));

const items = $input.all();
const config = $('Validate Input').first().json._config;
const maxLen = config?.crawler?.maxTextLength || 6000;
const textMap = {};

for (const item of items) {
  const slug = item.json.slug || '';

  // Handle crawl errors gracefully
  const statusCode = item.json.statusCode || item.json.headers?.['status'] || 200;
  const html = item.json.body || item.json.data || '';

  if (!html || typeof html !== 'string' || html.length < 50) {
    textMap[slug] = { text: '', word_count: 0, h_tags: [], meta: {},
      error: statusCode >= 400 ? `http_${statusCode}` : 'empty_response' };
    continue;
  }

  // ── Extract meta tags ──
  const meta = {};
  const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  meta.title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : '';
  const descMatch = html.match(/<meta\s+name=["']description["']\s+content=["']([\s\S]*?)["']/i);
  meta.description = descMatch ? descMatch[1].trim() : '';
  const robotsMatch = html.match(/<meta\s+name=["']robots["']\s+content=["']([\s\S]*?)["']/i);
  meta.robots = robotsMatch ? robotsMatch[1].trim().toLowerCase() : '';
  const canonicalMatch = html.match(/<link\s+rel=["']canonical["']\s+href=["']([\s\S]*?)["']/i);
  meta.canonical = canonicalMatch ? canonicalMatch[1].trim() : '';

  // Check noindex
  if (meta.robots.includes('noindex')) {
    textMap[slug] = { text: '', word_count: 0, h_tags: [], meta,
      warning: 'page_has_noindex' };
    continue;
  }

  // ── Strip non-content elements ──
  let clean = html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<aside[\s\S]*?<\/aside>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '');

  // ── Extract H-tags ──
  const hTags = [];
  const hRegex = /<(h[1-6])[^>]*>([\s\S]*?)<\/\1>/gi;
  let hMatch;
  while ((hMatch = hRegex.exec(html)) !== null) {
    const text = hMatch[2].replace(/<[^>]+>/g, '').trim();
    if (text) hTags.push({ tag: hMatch[1].toLowerCase(), text });
  }

  // ── Extract alt texts ──
  const altTexts = [];
  const altRegex = /alt=["']([\s\S]*?)["']/gi;
  let altMatch;
  while ((altMatch = altRegex.exec(html)) !== null) {
    if (altMatch[1].trim()) altTexts.push(altMatch[1].trim());
  }

  // ── Extract structured data (JSON-LD) ──
  let hasJsonLd = false;
  let jsonLdTypes = [];
  const ldRegex = /<script\s+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
  let ldMatch;
  while ((ldMatch = ldRegex.exec(html)) !== null) {
    hasJsonLd = true;
    try {
      const ld = JSON.parse(ldMatch[1]);
      if (ld['@type']) jsonLdTypes.push(ld['@type']);
      if (Array.isArray(ld['@graph'])) {
        ld['@graph'].forEach(g => { if (g['@type']) jsonLdTypes.push(g['@type']); });
      }
    } catch(e) {}
  }

  // ── Clean text extraction ──
  const text = clean
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&apos;/g, "'")
    .replace(/&#\d+;/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  // ── Compute text metrics ──
  const words = text.split(/\s+/).filter(w => w.length > 0);
  const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 3);
  const uniqueWords = [...new Set(words.map(w => w.toLowerCase()))];

  // ── Extract first paragraph ──
  const firstP = clean.match(/<p[^>]*>([\s\S]*?)<\/p>/i);
  const firstParagraph = firstP ? firstP[1].replace(/<[^>]+>/g, '').trim() : text.substring(0, 300);

  // ── Internal links count ──
  const internalLinks = (html.match(/<a\s[^>]*href=["']\/[^"']*["']/gi) || []).length;
  const externalLinks = (html.match(/<a\s[^>]*href=["']https?:\/\/[^"']*["']/gi) || []).length;

  textMap[slug] = {
    text: text.substring(0, maxLen),
    first_paragraph: firstParagraph.substring(0, 500),
    word_count: words.length,
    char_count: text.length,
    sentence_count: sentences.length,
    paragraph_count: (clean.match(/<p[\s>]/gi) || []).length,
    avg_sentence_len: sentences.length > 0 ? Math.round(words.length / sentences.length * 10) / 10 : 0,
    avg_word_len: words.length > 0 ? Math.round(words.reduce((s, w) => s + w.length, 0) / words.length * 10) / 10 : 0,
    unique_words_count: uniqueWords.length,
    unique_ratio: words.length > 0 ? Math.round(uniqueWords.length / words.length * 100) / 100 : 0,
    h_tags: hTags,
    alt_texts: altTexts,
    meta: meta,
    has_json_ld: hasJsonLd,
    json_ld_types: jsonLdTypes,
    internal_links: internalLinks,
    external_links: externalLinks
  };
}

// Get passthrough data from first item
const passthrough = items[0]?.json?._passthrough || {};

return [{ json: {
  text_map: textMap,
  crawled: Object.keys(textMap).length,
  skipped: false,
  structures: passthrough.structures || [],
  briefs_map: passthrough.briefs_map || {},
  existing_map: passthrough.existing_map || {},
  token: passthrough.token || ''
}}];

const data = $input.first().json;
const validate = $('Validate Input').first().json;
const config = validate._config;
const textMap = data.text_map || {};
const structures = data.structures || [];
const briefsMap = data.briefs_map || {};

const BATCH_SIZE = validate.batch_size || config.analysis.batchSize.default;
const batches = [];

for (let i = 0; i < structures.length; i += BATCH_SIZE) {
  const batch = structures.slice(i, i + BATCH_SIZE);
  const pagesData = batch.map((p, j) => {
    const slug = p.recommended_url || '';
    const brief = briefsMap[slug] || {};
    const pageText = textMap[slug] || {};
    const existing = data.existing_map?.[slug] || null;
    const mainKeyword = (p.main_keyword || '').toLowerCase().trim();
    const text = (pageText.text || '').toLowerCase();

    // ── PROGRAMMATIC keyword metrics (NOT LLM!) ──
    let keywordMetrics = {
      density_exact: 0, count_exact: 0,
      density_morphological: 0, count_morphological: 0,
      in_title: false, in_h1: false, in_first_paragraph: false,
      in_h2_h3: false, in_body: false, in_alt: false
    };

    if (mainKeyword && mainKeyword.length > 2 && text) {
      // Exact match
      const exactRegex = new RegExp(mainKeyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
      const exactMatches = text.match(exactRegex) || [];
      keywordMetrics.count_exact = exactMatches.length;
      const wordCount = pageText.word_count || 1;
      const keywordWordCount = mainKeyword.split(/\s+/).length;
      keywordMetrics.density_exact = Math.round(exactMatches.length * keywordWordCount / wordCount * 100 * 100) / 100;

      // Morphological (stem-based: first 4+ chars of each word)
      const keyWords = mainKeyword.split(/\s+/).filter(w => w.length > 3);
      if (keyWords.length > 0) {
        const stems = keyWords.map(w => w.substring(0, Math.min(w.length - 1, 5)));
        let morphCount = 0;
        const textWords = text.split(/\s+/);
        for (const tw of textWords) {
          if (stems.some(s => tw.startsWith(s))) morphCount++;
        }
        keywordMetrics.count_morphological = morphCount;
        keywordMetrics.density_morphological = Math.round(morphCount / wordCount * 100 * 100) / 100;
      }

      // Zone checks
      const meta = pageText.meta || {};
      keywordMetrics.in_title = (meta.title || '').toLowerCase().includes(mainKeyword);
      keywordMetrics.in_h1 = (pageText.h_tags || []).some(h => h.tag === 'h1' && h.text.toLowerCase().includes(mainKeyword));
      keywordMetrics.in_first_paragraph = (pageText.first_paragraph || '').toLowerCase().includes(mainKeyword);
      keywordMetrics.in_h2_h3 = (pageText.h_tags || []).some(h => ['h2','h3'].includes(h.tag) && h.text.toLowerCase().includes(mainKeyword));
      keywordMetrics.in_body = keywordMetrics.count_exact > 0;
      keywordMetrics.in_alt = (pageText.alt_texts || []).some(a => a.toLowerCase().includes(mainKeyword));
    }

    // ── Parse blocks/sections ──
    let blocks = [];
    try { blocks = typeof p.blocks === 'string' ? JSON.parse(p.blocks) : (p.blocks || []); } catch(e) {}
    let sections = [];
    try { sections = typeof brief.sections_json === 'string' ? JSON.parse(brief.sections_json) : (brief.sections_json || []); } catch(e) {}

    // ── Readability heuristic ──
    let readabilityScore = 7;
    const avgSentLen = pageText.avg_sentence_len || 0;
    if (avgSentLen > 30) readabilityScore -= 2;
    else if (avgSentLen > 25) readabilityScore -= 1;
    if (avgSentLen < 8 && avgSentLen > 0) readabilityScore -= 1;
    if ((pageText.unique_ratio || 0) < 0.3) readabilityScore -= 2;
    if ((pageText.unique_ratio || 0) > 0.7) readabilityScore += 1;
    if ((pageText.paragraph_count || 0) < 3 && pageText.word_count > 200) readabilityScore -= 1;
    readabilityScore = Math.min(Math.max(readabilityScore, 1), 10);

    // ── Word count deviation ──
    const targetWC = brief.word_count_target || p.total_word_count || 0;
    const actualWC = pageText.word_count || 0;
    const wcDeviation = targetWC > 0 ? Math.round((actualWC - targetWC) / targetWC * 100 * 10) / 10 : null;

    return {
      index: i + j + 1,
      page_type: p.page_type || 'commercial',
      cluster_name: p.cluster_name || '',
      slug: slug,
      main_keyword: p.main_keyword || '',
      h1: p.h1_template || '',
      title: p.title_template || '',
      description: p.description_template || '',
      target_word_count: targetWC,
      actual_word_count: actualWC,
      word_count_deviation_pct: wcDeviation,
      keyword_metrics: keywordMetrics,
      readability_heuristic: readabilityScore,
      blocks: blocks.map(b => ({
        name: b.block_name, words: b.word_count || 0,
        keywords: b.keywords_to_include || []
      })),
      sections: sections.map(s => s.section_name || s),
      text_stats: {
        sentence_count: pageText.sentence_count || 0,
        paragraph_count: pageText.paragraph_count || 0,
        avg_sentence_len: avgSentLen,
        avg_word_len: pageText.avg_word_len || 0,
        unique_ratio: pageText.unique_ratio || 0,
        h_tags: pageText.h_tags || [],
        alt_texts_count: (pageText.alt_texts || []).length,
        internal_links: pageText.internal_links || 0,
        external_links: pageText.external_links || 0,
        has_json_ld: pageText.has_json_ld || false,
        json_ld_types: pageText.json_ld_types || []
      },
      page_text_preview: (pageText.text || '').substring(0, 3000),
      meta: pageText.meta || {},
      previous_score: existing ? existing.relevance_score : null,
      previous_status: existing ? existing.status : null
    };
  });

  batches.push({
    batch_index: Math.floor(i / BATCH_SIZE) + 1,
    total_batches: Math.ceil(structures.length / BATCH_SIZE),
    pages: pagesData,
    batch_size: pagesData.length,
    niche: validate.niche,
    city: validate.city,
    project_id: validate.project_id,
    total_pages: structures.length,
    has_real_text: Object.keys(textMap).length > 0,
    token: data.token
  });
}

return batches.map(b => ({ json: b }));

const batch = $input.first().json;
const config = $('Validate Input').first().json._config;

const systemPrompt = `Ты — Senior SEO-аналитик текстовой релевантности экспертного уровня (15+ лет опыта). Год: 2026.

═══ РОЛЬ И КОНТЕКСТ ═══
Ты анализируешь текстовую релевантность страниц сайта. Тебе предоставлены:
- ТОЧНЫЕ вычисленные метрики (keyword density, counts, zones) — НЕ пересчитывай их, используй как есть
- Превью текста страницы для качественного анализа
- Данные о структуре и брифе

═══ ТВОЯ ЗАДАЧА ═══
На основе предоставленных метрик и текста выполни КАЧЕСТВЕННЫЙ анализ:

1. **LSI/Тематическое покрытие** (lsi_score: 1-10):
   - Наличие синонимов, связанных терминов, тематических n-грамм
   - Покрытие семантического ядра ниши "${batch.niche}"
   - Укажи КОНКРЕТНЫЕ недостающие термины в lsi_missing_terms

2. **Переоптимизация** (overoptimization_risk: low/medium/high):
   - Используй предоставленный keyword_density — если >3% для коммерческих или >2% для инфо → risk выше
   - Неестественные конструкции, keyword stuffing в тексте
   - Скрытый текст, чрезмерные повторы

3. **AEO-готовность** (aeo_ready: true/false, aeo_details):
   - Есть ли прямые ответы на вопросы (featured snippets format)
   - FAQ-блоки, How-to структура, определения
   - JSON-LD разметка

4. **E-E-A-T сигналы** (eeat_score: 1-10):
   - Experience: есть ли примеры из практики, кейсы
   - Expertise: профессиональная терминология, глубина раскрытия
   - Authoritativeness: ссылки на источники, данные, исследования
   - Trust: контактная информация, гарантии, лицензии

5. **Entity Salience** (entity_score: 1-10):
   - Насколько чётко текст связан с главной сущностью (keyword)
   - Связи с другими релевантными сущностями ниши
   - Гео-привязка к городу "${batch.city}"

6. **Content Gap** (content_gaps: [...]):
   - Какие темы/вопросы НЕ раскрыты, но должны быть для ниши
   - Сравнение с рекомендованными блоками/секциями

7. **Итоговая оценка** (relevance_score: 1-10):
   Формула: keyword_zones_coverage(20%) + lsi(20%) + eeat(15%) + entity(15%) + content_completeness(15%) + readability(15%)
   Используй предоставленные метрики для keyword_zones и readability.

═══ ШКАЛА ═══
• 9-10 (excellent): все зоны покрыты, LSI превосходно, E-E-A-T сильный
• 7-8 (good): мелкие пробелы, хорошая база
• 5-6 (average): существенные пробелы, требует доработки
• 3-4 (poor): критические проблемы с релевантностью
• 1-2 (critical): страница нерелевантна запросу

═══ SEVERITY ═══
• critical: влияет на ранжирование, требует немедленного исправления
• warning: заметное влияние, исправить в ближайшее время
• info: рекомендация для улучшения

