        'Content-Type': 'application/json'
      },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(90000)
    });

    if (resp.status === 429) {
      // Rate limited — wait longer
      const retryAfter = parseInt(resp.headers.get('retry-after') || '10') * 1000;
      console.log(`[v4.0] Rate limited, attempt ${attempt}/${MAX_RETRIES}, waiting ${retryAfter}ms`);
      await new Promise(r => setTimeout(r, retryAfter));
      continue;
    }

    if (!resp.ok) {
      const errText = await resp.text();
      lastError = `HTTP ${resp.status}: ${errText.substring(0, 200)}`;
      if (resp.status >= 500) {
        console.log(`[v4.0] Server error ${resp.status}, attempt ${attempt}/${MAX_RETRIES}`);
        await new Promise(r => setTimeout(r, RETRY_DELAY * attempt));
        continue;
      }
      break; // Client errors (4xx except 429) — don't retry
    }

    response = await resp.json();
    break; // Success
  } catch(e) {
    lastError = e.message;
    console.log(`[v4.0] Request failed attempt ${attempt}/${MAX_RETRIES}: ${e.message}`);
    if (attempt < MAX_RETRIES) {
      await new Promise(r => setTimeout(r, RETRY_DELAY * attempt));
    }
  }
}

