${result.critical_pages_count > 0 ? '\n🔴 Critical Pages:\n' + result.critical_pages.slice(0, 10).map(p => `  • ${p.slug} (score: ${p.score})`).join('\n') : '✅ No critical pages'}`;

// Send via configured webhook
if (config.alerts.enabled && config.alerts.webhookUrl) {
  try {
    let body, headers = { 'Content-Type': 'application/json' };

    if (config.alerts.provider === 'telegram') {
      body = JSON.stringify({
        chat_id: $env.TELEGRAM_CHAT_ID,
        text: alertMsg,
        parse_mode: 'HTML'
      });
    } else {
      // Slack / generic webhook
      body = JSON.stringify({ text: alertMsg });
    }

    const resp = await fetch(config.alerts.webhookUrl, {
      method: 'POST', headers, body,
      signal: AbortSignal.timeout(10000)
    });

    if (!resp.ok) {
      console.error('[v4.0] Alert send failed:', resp.status);
    }
  } catch(e) {
    console.error('[v4.0] Alert error:', e.message);
  }
}

console.log('[v4.0 ALERT]', alertMsg);
return [{ json: { ...result, alert_sent: true, alert_message: alertMsg } }];
